import React, { useEffect, useState } from 'react';
import Card from '../components/Card';
import { Chart as C, LineElement, BarElement, CategoryScale, LinearScale, PointElement, Tooltip, Legend } from 'chart.js';
import { Line, Bar } from 'react-chartjs-2';
import api from '../services/api';

C.register(LineElement, BarElement, CategoryScale, LinearScale, PointElement, Tooltip, Legend);

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const res = await api.get('/admin/dashboard-stats');
      setStats(res.data.data);
    } catch (err) {
      console.error("Error fetching stats:", err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div style={{ padding: 20 }}>Loading Dashboard...</div>;
  if (!stats) return <div style={{ padding: 20 }}>Error loading data.</div>;

  const { counts, charts, recentActivity } = stats;

  const savingsData = {
    labels: charts.savings.map(d => d._id),
    datasets: [{
      label: 'Savings Growth ($)',
      data: charts.savings.map(d => d.total),
      borderColor: '#34d399',
      backgroundColor: 'rgba(52, 211, 153, 0.2)',
      tension: 0.4,
      fill: true
    }]
  };

  const loanData = {
    labels: charts.loans.map(d => d._id),
    datasets: [{
      label: 'Loan Status',
      data: charts.loans.map(d => d.count),
      backgroundColor: ['#60a5fa', '#f87171', '#fbbf24', '#34d399'],
    }]
  };

  return (
    <div className="fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <h2 style={{ fontSize: '24px', fontWeight: 'bold', color: '#1f2937' }}>Admin Dashboard</h2>
        <button onClick={fetchStats} style={{ padding: '8px 16px', background: '#3b82f6', color: '#fff', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Refresh</button>
      </div>

      <div className="card-row" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '24px' }}>
        <Card title="Total Members" value={counts.members} icon="👥" color="#3b82f6" />
        <Card title="Total Staff" value={counts.staff} icon="🛡️" color="#6366f1" />
        <Card title="Total Savings" value={`$${counts.savings.toLocaleString()}`} icon="💰" color="#10b981" />
        <Card title="Total Loans" value={`$${counts.loans.toLocaleString()}`} icon="💸" color="#ef4444" />
        <Card title="Pending Requests" value={counts.pending} icon="⏳" color="#f59e0b" />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '24px', marginBottom: '24px' }}>
        <div className="card" style={{ padding: '20px', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
          <h4 style={{ marginTop: 0, marginBottom: '16px', color: '#374151' }}>Savings Growth</h4>
          <div style={{ height: '300px' }}>
            <Line data={savingsData} options={{ maintainAspectRatio: false, responsive: true }} />
          </div>
        </div>
        <div className="card" style={{ padding: '20px', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
          <h4 style={{ marginTop: 0, marginBottom: '16px', color: '#374151' }}>Loan Distribution</h4>
          <div style={{ height: '300px' }}>
            <Bar data={loanData} options={{ maintainAspectRatio: false, responsive: true }} />
          </div>
        </div>
      </div>

      <div className="card" style={{ padding: '20px', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
        <h4 style={{ marginTop: 0, marginBottom: '16px', color: '#374151' }}>Recent Activity</h4>
        {recentActivity.length === 0 ? <p className="text-muted">No recent activity.</p> : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {recentActivity.map((log, idx) => (
              <div key={idx} style={{ display: 'flex', alignItems: 'center', padding: '12px', background: '#f9fafb', borderRadius: '8px' }}>
                <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#3b82f6', marginRight: '12px' }}></div>
                <div>
                  <div style={{ fontWeight: '500', color: '#1f2937' }}>{log.action}</div>
                  <div style={{ fontSize: '12px', color: '#6b7280' }}>
                    by {log.performedBy?.fullName || 'Unknown'} • {new Date(log.timestamp).toLocaleString()}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
export default Dashboard;
